    type state_t is (IDLE, ONE_BUFFER, STREAMING, STREAMING_WAIT, DONE);
    signal state : state_t := IDLE;
    signal length : std_logic_vector(31 downto 0) := (others => '0');
    constant MORE_FLAG_INDEX : positive := 31;
