        procedure error_if_new_length is
        begin
            if length_wstb_i then
                overflow_error_o <= '1';
                state <= DONE;
            end if;
        end procedure;
    begin
        if rising_edge(clk_i) then
            if length_zero_event_o then
                streaming_mode_o <= '0';
                one_buffer_mode_o <= '0';
                state <= IDLE;
                completed_o <= '0';
            elsif abort_i then
                if state /= ONE_BUFFER then
                    state <= DONE;
                end if;
            else
                transfer_start_o <= '0';
                overflow_error_o <= '0';
                became_ready_event_o <= '0';
                case state is
                    -- state in which a new buffer is accepted
                    when IDLE =>
                        streaming_mode_o <= '0';
                        one_buffer_mode_o <= '0';
                        last_buffer_o <= '0';
                        if length_wstb_i then
                            if length_i(MORE_FLAG_INDEX) then
                                streaming_mode_o <= '1';
