        if sum_i(63) = '1' then
         result_neg <= '1';
         divider_i <= std_logic_vector((not(sum_i))+1);
         else
         result_neg <= '0';
         divider_i <= std_logic_vector(sum_i);
        end if;
      else
        trig_div_i <= '0';
      end if;
