    ongoing_trig_i      => pcap_dat_valid,
    pcap_armed_o        => pcap_armed,
    pcap_done_o         => pcap_done_o,
    pcap_start_event_o  => pcap_start_event_o,
    timestamp_o         => timestamp,
    pcap_status_o       => pcap_status
);


