    SHIft_SUM           => SHIFT_SUM,
    TRIG_EDGE           => TRIG_EDGE,
    --
    pos_bus_i           => pos_bus_i,
    bit_bus_i           => bit_bus_i,
    enable_i            => pcap_armed or ARM,
    gate_i              => gate,
    trig_i              => trig_en,
    timestamp_i         => timestamp,
